"use strict";parserFactory.register("rubymaybetranslations.com",()=>new RubymaybetranslationsParser);class RubymaybetranslationsParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("details a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("div.entry-content")}extractTitleImpl(e){return e.querySelector(".nv-page-title h1")}findChapterTitle(e){return e.querySelector("h1")}findParentNodeOfChapterLinkToRemoveAt(e){return util.moveIfParent(e,"p")}findCoverImageUrl(){return null}preprocessRawDom(e){util.removeChildElementsMatchingSelector(e,"#comments")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".entry-content > p")]}}